#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // 2. Drop the Product table if it exists
    auto drop_result = (sqlgen::drop<Product> | sqlgen::if_exists)(conn);
    if (!drop_result) {
        return false;
    }

    // 3. Create the Product table by inserting an empty vector
    auto create_table_result = sqlgen::insert(conn, std::vector<Product>{});
    if (!create_table_result) {
        return false;
    }

    // 4. Begin a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    // 5. Insert products in batches of 1000
    const size_t batch_size = 1000;
    for (size_t i = 0; i < products.size(); i += batch_size) {
        size_t end = std::min(i + batch_size, products.size());
        auto batch = std::vector<Product>(products.begin() + i, products.begin() + end);

        auto insert_result = sqlgen::insert(conn, batch);
        if (!insert_result) {
            // Rollback on failure
            conn->rollback();
            return false;
        }
    }

    // 6. Commit the transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
        // Rollback on commit failure
        conn->rollback();
        return false;
    }

    return true;
}

}  // namespace batch_insert_products
```

