#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Begin a transaction
  // 3. Delete users where last_login is less than '2025-01-01'
  // 4. Commit the transaction
  // 5. Return the operation result of commit
  return (conn | sqlgen::begin_transaction
          | (sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01"))
          | sqlgen::commit).transform([](auto&&) { return 0; })
                .or_else([](auto&& error) { return 1; });
}

} // namespace delete_inactive_users
```

## Explanation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Transaction Management**: 
   - Begins a transaction with `sqlgen::begin_transaction`
   - Commits the transaction with `sqlgen::commit`

3. **Conditional Deletion**:
   - Uses `sqlgen::delete_from<User>` to create a delete operation for the User table
   - Applies the condition with `sqlgen::where("last_login"_c < "2025-01-01")`
   - The `"last_login"_c` syntax uses the column literal operator from `sqlgen::literals`
   - The `<` operator creates a "less than" condition comparing the last_login column with the date string

4. **Result Handling**:
   - Uses `transform` to convert the successful result to `0` (success)
   - Uses `or_else` to convert any error to `1` (failure)
   - Returns the appropriate exit code

