    // Build WHERE conditions dynamically
    auto conditions = sqlgen::where("book_id"_c.is_not_null()); // Base condition

    if (filters.title_keyword) {
        conditions = conditions && "title"_c.like("%" + *filters.title_keyword + "%");
    }
    if (filters.min_year) {
        conditions = conditions && "year"_c >= *filters.min_year;
