        auto update_stmt = sqlgen::update<Document>(
            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
        ) | sqlgen::where("doc_id"_c.in(ids));

        // 4. Execute the update statement
        auto update_result = update_stmt(conn);
        if (!update_result) {
            conn->rollback();
            return false;
        }

        // 5. Commit the transaction
        auto commit_result = conn->commit();
        if (!commit_result) {
            conn->rollback();
            return false;
        }

    } catch (...) {
        // 6. Rollback on any error
        conn->rollback();
        return false;
    }

    return true;
}

