namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_id, int to_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) return false;
  create_table<Account>(conn);

  // Check sufficient funds
  const auto get_from =
      select_from<Account>(col<"balance"> | as<"balance">) |
      where(col<"account_id"> == from_id) | to<std::vector<double>>;
  auto from_bal = get_from(conn).value();
  if (from_bal.empty() || from_bal[0] < amount) {
    return false;
  }

  auto txn_res = begin_transaction(conn.value());
  if (!txn_res) return false;
  auto txn = txn_res.value();

  std::string sql1 = "UPDATE Account SET balance = balance - " + std::to_string(amount) +
                     " WHERE account_id = " + std::to_string(from_id) + ";";
  std::string sql2 = "UPDATE Account SET balance = balance + " + std::to_string(amount) +
                     " WHERE account_id = " + std::to_string(to_id) + ";";

  auto exec1_res = exec(txn, sql1);
  if (!exec1_res) {
    return false;
  }

  auto exec2_res = exec(txn, sql2);
  if (!exec2_res) {
    return false;
  }

  auto commit_res = commit(txn);
  return commit_res.has_value();
}

