bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // 1. Connect to the SQLite database "test_db.sqlite"
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Use sqlgen::write with or_replace=true to perform upsert operation
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false; // Write operation failed
  }

  // 3. Use sqlgen::read to verify the upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false; // Read operation failed
  }

  auto read_items = read_result.value();

  // 4. Verify that the upsert operation successfully inserted/updated all items
  // Create a map of original items for comparison
  std::unordered_map<int, Inventory> original_map;
  for (const auto& item : items) {
    original_map[item.item_id.value()] = item;
  }

  // Verify the count and each item's data
  if (read_items.size() != items.size()) {
    return false; // Item count mismatch
  }

  for (const auto& item : read_items) {
    auto original_it = original_map.find(item.item_id.value());
    if (original_it == original_map.end()) {
      return false; // Found an item not in the original list
    }

    // Verify all fields match
    if (original_it->second.name != item.name ||
        original_it->second.quantity != item.quantity) {
      return false; // Data mismatch for item
    }

    original_map.erase(original_it);
  }

  // Ensure all original items were accounted for
  if (!original_map.empty()) {
    return false; // Missing items in the result
  }

  return true; // All verifications passed
}

}  // namespace upsert_inventory_items
