#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  std::string city;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
  sqlgen::PrimaryKey<std::tuple<int, int>> id;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn | sqlgen::create_table<User>;
  conn | sqlgen::create_table<Friendship>;

  // Insert data
  conn | sqlgen::write(users);
  conn | sqlgen::write(friendships);

  // Query 1: Mutual friends using self-join and subquery
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_t1 | sqlgen::as<"user1_name">,
      "username"_t2 | sqlgen::as<"user2_name">
    )
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3)
    | sqlgen::where("user_id"_t1 < "user_id"_t3)
    | sqlgen::group_by("user_id"_t1, "user_id"_t3)
    | sqlgen::having(sqlgen::count() > 0);

  // Execute queries and collect results
  auto mutual_friends = mutual_friends_query(conn);

  std::vector<FriendConnection> result;
  for (const auto& row : mutual_friends) {
    result.push_back(FriendConnection{
        .user1_name = row.template get<"user1_name">(),
        .user2_name = row.template get<"user2_name">()
    });
  }

  return result;
}

}  // namespace analyze_social_network
