#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create the Account table by writing an empty container
  std::vector<Account> empty_accounts;
  auto create_result = sqlgen::write(conn, empty_accounts);
  if (!create_result) {
    return false;
  }

  // 3. Update Account records using set() operations
  // First update: set balance to 1000.0 and status to "active" for account_id=1
  Account update1;
  update1.account_id = 1;
  update1.balance = 1000.0;
  update1.status = "active";

  // Second update: set balance to 2000.0 and status to "inactive" for account_id=2
  Account update2;
  update2.account_id = 2;
  update2.balance = 2000.0;
  update2.status = "inactive";

  std::vector<Account> updates{update1, update2};
  auto update_result = sqlgen::write(conn, updates);
  if (!update_result) {
    return false;
  }

  // 4. Verify the changes by reading the updated records
  auto read_result = sqlgen::read<std::vector<Account>>(conn);
  if (!read_result) {
    return false;
  }

  auto accounts = *read_result;
  bool verification_passed = true;

  // Check first update
  bool found1 = false;
  for (const auto& acc : accounts) {
    if (acc.account_id == 1) {
      found1 = true;
      if (acc.balance != 1000.0 || acc.status != "active") {
        verification_passed = false;
        break;
      }
    }
  }
  if (!found1) verification_passed = false;

  // Check second update  
  bool found2 = false;
  for (const auto& acc : accounts) {
    if (acc.account_id == 2) {
      found2 = true;
      if (acc.balance != 2000.0 || acc.status != "inactive") {
        verification_passed = false;
        break;
      }
    }
  }
  if (!found2) verification_passed = false;

  return verification_passed;
}

}  // namespace update_set_operations
```

