  // 3. Apply inner join to connect User and Post tables
  | sqlgen::inner_join<User, "t2">("user_id"_t1 == "user_id"_t2)
  // 4. Apply group_by with the grouping columns
  | sqlgen::group_by("user_id"_t1, "name"_t2)
  // 5. Use to<> to specify the return type
  | sqlgen::to<std::vector<Stats>>;

  // 6. Execute the query and return the result
  return query(conn).value();
}

